<span class="line"><span style="color:#98C379;">&quot; &quot;</span><span style="color:#56B6C2;"> !=</span><span style="color:#98C379;"> &quot;0&quot;</span><span style="color:#ABB2BF;">; </span><span style="color:#7F848E;font-style:italic;">//true</span></span>
